# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from flask_graphql import GraphQLView
import graphene

class CategoryType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()

class ReviewType(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()

class ProductType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType)

categories_data = [
    {"id": "1", "name": "Electronics"},
    {"id": "2", "name": "Books"}
]

products_data = [
    {"id": "1", "name": "Smartphone", "description": "Latest model", "price": 699.99, "category_id": "1"},
    {"id": "2", "name": "Laptop", "description": "Ultrabook", "price": 1299.99, "category_id": "1"},
    {"id": "3", "name": "Novel", "description": "Bestseller", "price": 19.99, "category_id": "2"}
]

reviews_data = [
    {"id": "1", "product_id": "1", "user": "John", "rating": 5, "comment": "Excellent!"},
    {"id": "2", "product_id": "1", "user": "Jane", "rating": 4, "comment": "Very good!"},
    {"id": "3", "product_id": "3", "user": "Bob", "rating": 3, "comment": "Average"}
]

def resolve_category(category_id):
    for cat in categories_data:
        if cat["id"] == category_id:
            return cat
    return None

def resolve_reviews_for_product(product_id):
    return [r for r in reviews_data if r["product_id"] == product_id]

class Query(graphene.ObjectType):
    product = graphene.Field(ProductType, id=graphene.ID(required=True))
    products = graphene.List(ProductType)
    category = graphene.Field(CategoryType, id=graphene.ID(required=True))
    categories = graphene.List(CategoryType)
    review = graphene.Field(ReviewType, id=graphene.ID(required=True))
    reviews = graphene.List(ReviewType)

    def resolve_product(self, info, id):
        for prod in products_data:
            if prod["id"] == id:
                cat_data = resolve_category(prod["category_id"])
                rev_data = resolve_reviews_for_product(prod["id"])
                return ProductType(
                    id=prod["id"],
                    name=prod["name"],
                    description=prod["description"],
                    price=prod["price"],
                    category=CategoryType(id=cat_data["id"], name=cat_data["name"]) if cat_data else None,
                    reviews=[ReviewType(**r) for r in rev_data]
                )
        return None

    def resolve_products(self, info):
        result = []
        for prod in products_data:
            cat_data = resolve_category(prod["category_id"])
            rev_data = resolve_reviews_for_product(prod["id"])
            result.append(
                ProductType(
                    id=prod["id"],
                    name=prod["name"],
                    description=prod["description"],
                    price=prod["price"],
                    category=CategoryType(id=cat_data["id"], name=cat_data["name"]) if cat_data else None,
                    reviews=[ReviewType(**r) for r in rev_data]
                )
            )
        return result

    def resolve_category(self, info, id):
        for cat in categories_data:
            if cat["id"] == id:
                return CategoryType(id=cat["id"], name=cat["name"])
        return None

    def resolve_categories(self, info):
        return [CategoryType(id=cat["id"], name=cat["name"]) for cat in categories_data]

    def resolve_review(self, info, id):
        for r in reviews_data:
            if r["id"] == id:
                return ReviewType(**r)
        return None

    def resolve_reviews(self, info):
        return [ReviewType(**r) for r in reviews_data]

schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True  # Introspection is enabled by default
    )
)

if __name__ == "__main__":
    app.run(debug=True)